mapper.select:
SELECT id, message_id, interface_id, direction, source_system, target_system, status, request_body, response_body, error_message, retry_count, processing_ms, kafka_partition, kafka_offset, created_at, processed_at FROM eai_message_history
AND interface_id = #{interfaceId}
AND status = #{status}
AND (message_id LIKE CONCAT('%', #{keyword}, '%') OR source_system LIKE CONCAT('%', #{keyword}, '%') OR target_system LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY created_at DESC LIMIT 500

mapper.update:
UPDATE eai_message_history
SET    status = 'DLQ'
WHERE  message_id = #{messageId}

UPDATE eai_message_history
SET    retry_count = #{retryCount}
WHERE  id = #{id}
